import{_ as t,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"認証失敗: 401 エラートラブルシューティング | Antigravity-Manager","description":"Antigravity Tools プロキシの認証メカニズムを学び、401 エラーをトラブルシューティングします。auth_mode、api_key、Header の順序で問題を特定し、auto モードルールと /healthz 豁免を理解し、Header 優先度の誤判を回避します。","frontmatter":{"title":"認証失敗: 401 エラートラブルシューティング | Antigravity-Manager","sidebarTitle":"3分で 401 を解決","subtitle":"401/認証失敗：まず auth_mode を見て、次に Header を見る","description":"Antigravity Tools プロキシの認証メカニズムを学び、401 エラーをトラブルシューティングします。auth_mode、api_key、Header の順序で問題を特定し、auto モードルールと /healthz 豁免を理解し、Header 優先度の誤判を回避します。","tags":["FAQ","認証","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"ja/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function i(s,e,l,c,h,n){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="_401-認証失敗-まず-auth-mode-を見て、次に-header-を見る" tabindex="-1">401/認証失敗：まず auth_mode を見て、次に Header を見る <a class="header-anchor" href="#_401-認証失敗-まず-auth-mode-を見て、次に-header-を見る" aria-label="Permalink to &quot;401/認証失敗：まず auth_mode を見て、次に Header を見る&quot;">​</a></h1><h2 id="学んだ後できること" tabindex="-1">学んだ後できること <a class="header-anchor" href="#学んだ後できること" aria-label="Permalink to &quot;学んだ後できること&quot;">​</a></h2><ul><li>3 分以内に 401 が Antigravity Tools の認証ミドルウェアにブロックされたか判断できる</li><li><code>proxy.auth_mode</code> の 4 つのモード（特に <code>auto</code>）が現在の設定でどの「実際の有効値」になるのか明確にできる</li><li>正しい API Key Header（および Header 優先度の罠を回避）を使ってリクエストを通す</li></ul><h2 id="現在の悩み" tabindex="-1">現在の悩み <a class="header-anchor" href="#現在の悩み" aria-label="Permalink to &quot;現在の悩み&quot;">​</a></h2><p>クライアントがローカルリバースプロキシを呼び出すときに <code>401 Unauthorized</code> エラーを受信：</p><ul><li>Python/OpenAI SDK：<code>AuthenticationError</code> をスロー</li><li>curl：<code>HTTP/1.1 401 Unauthorized</code> を返す</li><li>HTTP クライアント：レスポンスステータスコード 401</li></ul><h2 id="_401-認証失敗とは" tabindex="-1">401/認証失敗とは？ <a class="header-anchor" href="#_401-認証失敗とは" aria-label="Permalink to &quot;401/認証失敗とは？&quot;">​</a></h2><p><strong>401 Unauthorized</strong> は Antigravity Tools で最も一般的な意味は：プロキシが認証を有効にしていて（<code>proxy.auth_mode</code> で決定）、リクエストが正しい API Key を持っていないか、優先度が高くて不一致の Header を持っているため、<code>auth_middleware()</code> が直接 401 を返したことです。</p><div class="info custom-block"><p class="custom-block-title">まず「プロキシがブロックしているか」を確認</p><p>アップストリームプラットフォームも 401 を返す可能性がありますが、この FAQ は「プロキシ認証による 401」のみを処理します。以下の <code>/healthz</code> で素早く区別できます。</p></div><h2 id="高速トラブルシューティング-この順序で実行" tabindex="-1">高速トラブルシューティング（この順序で実行） <a class="header-anchor" href="#高速トラブルシューティング-この順序で実行" aria-label="Permalink to &quot;高速トラブルシューティング（この順序で実行）&quot;">​</a></h2><h3 id="第-1-ステップ-healthz-で「認証があなたをブロックしているか」を判断" tabindex="-1">第 1 ステップ：<code>/healthz</code> で「認証があなたをブロックしているか」を判断 <a class="header-anchor" href="#第-1-ステップ-healthz-で「認証があなたをブロックしているか」を判断" aria-label="Permalink to &quot;第 1 ステップ：`/healthz` で「認証があなたをブロックしているか」を判断&quot;">​</a></h3><p><strong>なぜか</strong><code>all_except_health</code> は <code>/healthz</code> を通すが、他のルートをブロックします。これにより 401 がプロキシ認証層から来るかを素早く特定できます。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 認証 Header なし</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>表示されるべきもの</strong></p><ul><li><code>auth_mode=all_except_health</code>（または <code>auto</code> で <code>allow_lan_access=true</code>）の時：通常 <code>200</code> を返す</li><li><code>auth_mode=strict</code> の時：<code>401</code> を返す</li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> はルート層で GET</p><p>プロキシはルートで <code>GET /healthz</code> を登録しています（<code>src-tauri/src/proxy/server.rs</code> 参照）。</p></div><hr><h3 id="第-2-ステップ-auth-mode-の「実際の有効値」を確認-特に-auto" tabindex="-1">第 2 ステップ：<code>auth_mode</code> の「実際の有効値」を確認（特に <code>auto</code>） <a class="header-anchor" href="#第-2-ステップ-auth-mode-の「実際の有効値」を確認-特に-auto" aria-label="Permalink to &quot;第 2 ステップ：`auth_mode` の「実際の有効値」を確認（特に `auto`）&quot;">​</a></h3><p><strong>なぜか</strong><code>auto</code> は「独立した戦略」ではなく、<code>allow_lan_access</code> に基づいて実際に実行するモードを計算します。</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>追加条件</th><th>実際の有効値（effective mode）</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>GUI の API Proxy ページで確認できます</strong>：<code>Allow LAN Access</code> と <code>Auth Mode</code>。</p><hr><h3 id="第-3-ステップ-api-key-が空でなく、同じ値を使っているか確認" tabindex="-1">第 3 ステップ：<code>api_key</code> が空でなく、同じ値を使っているか確認 <a class="header-anchor" href="#第-3-ステップ-api-key-が空でなく、同じ値を使っているか確認" aria-label="Permalink to &quot;第 3 ステップ：`api_key` が空でなく、同じ値を使っているか確認&quot;">​</a></h3><p><strong>なぜか</strong> 認証が有効な時、<code>proxy.api_key</code> が空だと、<code>auth_middleware()</code> はすべてのリクエストを直接拒否し、エラーログを記録します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>表示されるべきもの</strong></p><ul><li>API Proxy ページで <code>sk-</code> で始まる key が見える（デフォルト値は <code>ProxyConfig::default()</code> で自動生成）</li><li>「Regenerate/編集」をクリックして保存すると、外部リクエストはすぐに新しい key で検証される（再起動不要）</li></ul><hr><h3 id="第-4-ステップ-最も簡単な-header-で一度試す-まず複雑な-sdk-を使わない" tabindex="-1">第 4 ステップ：最も簡単な Header で一度試す（まず複雑な SDK を使わない） <a class="header-anchor" href="#第-4-ステップ-最も簡単な-header-で一度試す-まず複雑な-sdk-を使わない" aria-label="Permalink to &quot;第 4 ステップ：最も簡単な Header で一度試す（まず複雑な SDK を使わない）&quot;">​</a></h3><p><strong>なぜか</strong> ミドルウェアは優先的に <code>Authorization</code> を読み、次に <code>x-api-key</code>、最後に <code>x-goog-api-key</code> を読みます。複数の Header を同時に送った場合、前の方が間違っていれば、後の方が合っていても使われません。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 推奨書き方：Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>表示されるべきもの</strong>：<code>HTTP/1.1 200 OK</code>（または少なくとも 401 ではなくなる）</p><div class="info custom-block"><p class="custom-block-title">プロキシの Authorization 互換性の詳細</p><p><code>auth_middleware()</code> は <code>Authorization</code> の値を <code>Bearer </code> プレフィックスで一度剥がします。<code>Bearer </code> プレフィックスがない場合も、値全体を key として比較します。ドキュメントは引き続き <code>Authorization: Bearer &lt;key&gt;</code> を推奨します（共通 SDK の約定により適合）。</p></div><p><strong><code>x-api-key</code> を使わなければならない場合</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="一般的な罠-すべてソースコードで実際に発生する" tabindex="-1">一般的な罠（すべてソースコードで実際に発生する） <a class="header-anchor" href="#一般的な罠-すべてソースコードで実際に発生する" aria-label="Permalink to &quot;一般的な罠（すべてソースコードで実際に発生する）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>現象</th><th>真の原因</th><th>どう直すべきか</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code> で、ローカル呼び出しは依然として 401</td><td><code>allow_lan_access=true</code> により <code>auto</code> が <code>all_except_health</code> として有効になる</td><td><code>allow_lan_access</code> を閉じるか、クライアントに key を持たせる</td></tr><tr><td>「明らかに x-api-key を持っているのに」と思っても、依然として 401</td><td>同時に不一致の <code>Authorization</code> を持っていて、ミドルウェアがそれを優先的に使う</td><td>多余な Header を削除し、確実に正しいものだけを残す</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> でも 401</td><td><code>Bearer</code> の後にスペースがなく、<code>Bearer </code> プレフィックスで剥がせない</td><td><code>Authorization: Bearer &lt;key&gt;</code> に変更</td></tr><tr><td>すべてのリクエストが 401 で、ログに <code>api_key is empty</code> が現れる</td><td><code>proxy.api_key</code> が空</td><td>GUI で再度生成/設定して空でない key を作る</td></tr></tbody></table><h2 id="レッスンまとめ" tabindex="-1">レッスンまとめ <a class="header-anchor" href="#レッスンまとめ" aria-label="Permalink to &quot;レッスンまとめ&quot;">​</a></h2><ul><li>まず <code>/healthz</code> で 401 がプロキシ認証層から来るかを特定</li><li>次に <code>auth_mode</code> を確認（特に <code>auto</code> の effective mode）</li><li>最後に確実に正しい Header を一つ持って検証（Header 優先度の罠を回避）</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../429-rotation/">429/容量エラー：アカウントローテーションの正しい期待とモデル容量枯渇の誤解</a></strong> を学びます</p><p>学べること：</p><ul><li>429 は「クォータ不足」か「アップストリームレート制限」か</li><li>アカウントローテーションの正しい期待（いつ自動的に切り替わるか、いつ切り替わらないか）</li><li>設定で 429 の確率を下げる方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>ProxyAuthMode 列挙</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key とデフォルト値</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>auto モード解析（effective_auth_mode）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>認証ミドルウェア（Header 抽出と優先度、/healthz 豁免、OPTIONS 通過）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>/healthz ルート登録とミドルウェア順序</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>認証ドキュメント（モードとクライアント約定）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>重要な列挙</strong>：</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>：認証モード</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>：<code>auto</code> を真の戦略に解析</li><li><code>auth_middleware()</code>：認証を実行（Header 抽出順序と /healthz 豁免を含む）</li></ul></details>',45)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
